    48			},
    49			"truncate": {
    50				command: newDBTruncateCmd(flags),
    51				want:    "truncate database is destructive for projects/test-project/instances/test-instance/databases/test-database; truncation only respects interleave order, so foreign-key-only relationships may need manual handling; rerun with --force to confirm",
    52			},
    53		}
    54	
    55		for name, tt := range tests {
    56			t.Run(name, func(t *testing.T) {
